import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getMyPurchaseRequests } from '../../services/dataService';
import { formatDate, formatCurrency } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';

const CustomerPurchaseRequests = () => {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await getMyPurchaseRequests();
        setRequests(res.data.data);
      } catch (err) { console.error(err); }
      finally { setLoading(false); }
    };
    fetch();
  }, []);

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header">
        <h1>My Purchase Requests</h1>
        <Link to="/properties" className="btn btn-primary">Browse Properties</Link>
      </div>

      {requests.length === 0 ? (
        <div className="empty-state">
          <p>You haven't made any purchase requests yet.</p>
          <Link to="/properties" className="btn btn-primary">Browse Properties</Link>
        </div>
      ) : (
        <div className="table-container">
          <table>
            <thead>
              <tr><th>Property</th><th>Price</th><th>Status</th><th>Date</th><th>Admin Notes</th></tr>
            </thead>
            <tbody>
              {requests.map(req => (
                <tr key={req._id}>
                  <td>
                    {req.property ? (
                      <Link to={`/customer/properties/${req.property._id}`}>{req.property.title}</Link>
                    ) : 'N/A'}
                  </td>
                  <td>{req.property ? formatCurrency(req.property.price) : 'N/A'}</td>
                  <td><StatusBadge status={req.status} /></td>
                  <td>{formatDate(req.createdAt)}</td>
                  <td>{req.adminNotes || '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default CustomerPurchaseRequests;
